parameters.jsCode:
// Get AI response text
const responseData = $input.first().json;
const aiText = responseData?.choices?.[0]?.message?.content || '';

console.log('Raw AI Response:', aiText);

let parsedData = { items: [] };

try {
  // Clean response - remove markdown/code blocks
  let clean = aiText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  // Extract JSON object if mixed with text
  const jsonMatch = clean.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    clean = jsonMatch[0];
  }

  parsedData = JSON.parse(clean);

  // Normalize: handle if AI returned direct array
  if (Array.isArray(parsedData)) {
    parsedData = { items: parsedData };
  }

  // Ensure items array exists
  if (!parsedData.items || !Array.isArray(parsedData.items)) {
    parsedData.items = [];
  }

  // Validate & clean each item
  parsedData.items = parsedData.items
    .filter(item => item && item.name && String(item.name).trim() !== '')
    .map(item => ({
      name: String(item.name || '').trim(),
      qty: parseFloat(item.qty || item.quantity || item.amount || 1) || 1,
      unit: String(item.unit || item.uom || 'kg').toLowerCase().trim(),
      price: parseFloat(item.price || item.rate || item.cost || item.unit_price || 0) || 0
    }));

  console.log('Parsed items:', JSON.stringify(parsedData.items));

} catch (err) {
  console.error('Parse error:', err.message);
  parsedData = {
    items: [],
    error: 'Bill se data parse nahi hua',
    raw_response: aiText
  };
}

return [{ json: parsedData }];
